DROP TABLE IF EXISTS `users`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `users` (
  `user_id` int NOT NULL AUTO_INCREMENT,
  `user_name` varchar(255) DEFAULT NULL,
  `email` varchar(255) DEFAULT NULL,
  `join_date` date DEFAULT NULL,
  `current_plan_id` int DEFAULT NULL,
  `mobile_number` varchar(20) DEFAULT NULL,
  `city` varchar(100) DEFAULT NULL,
  `churn_score` double DEFAULT NULL,
  `risk_level` varchar(50) DEFAULT NULL,
  `monthly_usage` double DEFAULT NULL,
  `recommended_plan` varchar(100) DEFAULT NULL,
  PRIMARY KEY (`user_id`),
  UNIQUE KEY `email` (`email`),
  KEY `idx_user_email` (`email`)
) ENGINE=InnoDB AUTO_INCREMENT=606 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

